<div class="row"><div class="col-md-4"><div class="form-group"><label>Valor Base</label><input type="number" step="0.01" class="form-control" name="valor_base" id="edit_valor_base"></div></div><div class="col-md-4"><div class="form-group"><label>Alíquota</label><input type="number" step="0.01" class="form-control" name="aliquota" id="edit_aliquota"></div></div><div class="col-md-4"><div class="form-group"><label>Valor Retenção</label><input type="number" step="0.01" class="form-control" name="valor_retencao" id="edit_valor_retencao"></div></div></div>
