</div><div class="modal-footer"><button type="button" class="btn btn-secondary" data-dismiss="modal">Cancelar</button><button type="submit" class="btn btn-primary">Atualizar</button></div></form></div></div></div>

<script>
$(document).ready(function() {
    if (!$.fn.DataTable.isDataTable('#tbl_retencoes')) $('#tbl_retencoes').DataTable({ "info": true, "searching": true, "paging": true, "pageLength": 15, "order": [[5, 'desc']], "language": { "url": "//cdn.datatables.net/plug-ins/9dcbecd42ad/i18n/Portuguese.json" } });
    $('.btn-edit').on('click', function() {
        $.getJSON('<?= base_url(); ?>retencoes/get/' + $(this).data('id'), function(data) {
            $('#edit_id').val(data.idretencao); $('#edit_tipo').val(data.tipo); $('#edit_clientesid').val(data.clientesid);
            $('#edit_valor_base').val(data.valor_base); $('#edit_aliquota').val(data.aliquota); $('#edit_valor_retencao').val(data.valor_retencao);
            if (data.data_retencao) $('#edit_data_retencao').val(data.data_retencao);
            $('#edit_status').val(data.status);
            $('#modalEdit').modal('show');
        });
    });
});
</script>
